-- FSI_DEMO_DB.WEALTH_MANAGEMENT.PORTFOLIOS

CREATE OR REPLACE TABLE FSI_DEMO_DB.WEALTH_MANAGEMENT.PORTFOLIOS (

    PORTFOLIO_ID VARCHAR(20) NOT NULL,
    CLIENT_ID VARCHAR(20),
    PORTFOLIO_NAME VARCHAR(100),
    PORTFOLIO_TYPE VARCHAR(50),
    INCEPTION_DATE DATE,
    BENCHMARK VARCHAR(50),
    TOTAL_VALUE NUMBER(18,2),
    CASH_BALANCE NUMBER(18,2),
    EQUITY_ALLOCATION NUMBER(5,4),
    FIXED_INCOME_ALLOCATION NUMBER(5,4),
    ALTERNATIVE_ALLOCATION NUMBER(5,4),
    CASH_ALLOCATION NUMBER(5,4),
    YTD_RETURN NUMBER(8,4),
    ONE_YEAR_RETURN NUMBER(8,4),
    THREE_YEAR_RETURN NUMBER(8,4),
    SHARPE_RATIO NUMBER(6,4),
    VOLATILITY NUMBER(6,4),
    LAST_REBALANCE_DATE DATE,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (PORTFOLIO_ID)

);



